distributions = []
for a in range(31):
    for b in range(31):
        c = 30 - a - b
        if c < 0:
            continue
        vals = sorted([a, b, c])
        # Constraint: some box >= 2
        if max(vals) < 2:
            continue
        # Constraint: some pair differs by exactly 6
        has_six = False
        if len(set(vals)) < 3:
            pairs = [(vals[0],vals[1]),(vals[0],vals[2]),(vals[1],vals[2])]
        else:
            pairs = [(vals[0],vals[1]),(vals[0],vals[2]),(vals[1],vals[2])]
        for x,y in pairs:
            if abs(x-y) == 6:
                has_six = True
                break
        if not has_six:
            continue
        distributions.append(tuple(vals))

distributions = sorted(set(distributions))
print(f"Total valid distributions: {len(distributions)}")
print("\nAll distributions (sorted values):")
for d in distributions:
    print(d)
